// Validate payload and enforce memory_write approval gate
const body = $input.first().json.body || $input.first().json;
const action = body.action || 'write';

if (action === 'write') {
  const required = ['session_id', 'user_input_hash', 'context_summary', 'approved_by'];
  for (const field of required) {
    if (!body[field]) throw new Error(`Missing required field: ${field}`);
  }

  if (body.approved_by !== 'user_explicit') {
    throw new Error('memory_write gate: approved_by must be user_explicit. Automatic writes are not permitted.');
  }

  const sessionId = body.session_id;
  const timestamp = new Date().toISOString();
  const memoryId = `sess_${sessionId}_${Date.now()}`;
  const memoryType = body.memory_type || 'working';
  const ttlSeconds = memoryType === 'episodic' ? 2592000 : 14400;
  const contextTruncated = (body.context_summary || '').substring(0, 1500);

  return {
    action: 'write',
    memory_id: memoryId,
    session_id: sessionId,
    user_input_hash: body.user_input_hash,
    context_summary: contextTruncated,
    memory_type: memoryType,
    ttl_seconds: ttlSeconds,
    approved_by: body.approved_by,
    timestamp,
    source: 'session-memory-bridge',
    collection: 'merlin_session',
    embedding_model: 'nomic-embed-text',
    embedding_prompt: `${sessionId} ${contextTruncated.substring(0, 500)}`
  };
} else if (action === 'read') {
  if (!body.session_id && !body.query) {
    throw new Error('Read action requires session_id or query field');
  }
  const query = body.query || body.session_id;
  return {
    action: 'read',
    session_id: body.session_id || null,
    query,
    top_k: body.top_k || 3,
    timestamp: new Date().toISOString(),
    collection: 'merlin_session',
    embedding_model: 'nomic-embed-text',
    embedding_prompt: query
  };
} else {
  throw new Error(`Unknown action: ${action}. Use 'write' or 'read'.`);
}
